package soroushlib

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"crypto/sha1"
	"crypto/sha256"
	"fmt"
	"math/big"
)

// ──────────────────────────────────────────────────────────────────────────────
// AES-IGE (Infinite Garble Extension) — used for MTProto message encryption
// ──────────────────────────────────────────────────────────────────────────────

func aesECB(key, block []byte, encrypt bool) []byte {
	c, _ := aes.NewCipher(key)
	out := make([]byte, len(block))
	if encrypt {
		c.Encrypt(out, block)
	} else {
		c.Decrypt(out, block)
	}
	return out
}

func XorBytes(a, b []byte) []byte {
	n := len(a)
	if len(b) < n {
		n = len(b)
	}
	out := make([]byte, n)
	for i := 0; i < n; i++ {
		out[i] = a[i] ^ b[i]
	}
	return out
}

func AesIGEEncrypt(data, key, iv []byte) []byte {
	if len(data)%16 != 0 {
		pad := make([]byte, 16-len(data)%16)
		data = append(data, pad...)
	}
	ivO := make([]byte, 16)
	ivI := make([]byte, 16)
	copy(ivO, iv[0:16])
	copy(ivI, iv[16:32])

	out := make([]byte, 0, len(data))
	for i := 0; i < len(data); i += 16 {
		plain := data[i : i+16]
		encrypted := XorBytes(aesECB(key, XorBytes(plain, ivO), true), ivI)
		out = append(out, encrypted...)
		copy(ivI, plain)
		copy(ivO, encrypted)
	}
	return out
}

func AesIGEDecrypt(data, key, iv []byte) []byte {
	if len(data)%16 != 0 {
		pad := make([]byte, 16-len(data)%16)
		data = append(data, pad...)
	}
	ivO := make([]byte, 16)
	ivI := make([]byte, 16)
	copy(ivO, iv[0:16])
	copy(ivI, iv[16:32])

	out := make([]byte, 0, len(data))
	for i := 0; i < len(data); i += 16 {
		cipherBlock := data[i : i+16]
		plain := XorBytes(aesECB(key, XorBytes(cipherBlock, ivI), false), ivO)
		out = append(out, plain...)
		copy(ivO, cipherBlock)
		copy(ivI, plain)
	}
	return out
}

// ──────────────────────────────────────────────────────────────────────────────
// AES-CTR — used for obfuscated transport layer
// ──────────────────────────────────────────────────────────────────────────────

type AesCTRCipher struct {
	stream cipher.Stream
}

func NewAESCTR(key, iv []byte) *AesCTRCipher {
	block, _ := aes.NewCipher(key)
	return &AesCTRCipher{stream: cipher.NewCTR(block, iv)}
}

func (c *AesCTRCipher) Update(data []byte) []byte {
	out := make([]byte, len(data))
	c.stream.XORKeyStream(out, data)
	return out
}

// ──────────────────────────────────────────────────────────────────────────────
// Hash helpers
// ──────────────────────────────────────────────────────────────────────────────

func Sha1Sum(data []byte) []byte {
	h := sha1.Sum(data)
	return h[:]
}

func Sha256Sum(data []byte) []byte {
	h := sha256.Sum256(data)
	return h[:]
}

// ──────────────────────────────────────────────────────────────────────────────
// Generate key and IV for MTProto message encryption
// ──────────────────────────────────────────────────────────────────────────────

func GenerateKeyIV(authKey, msgKey []byte, client bool) (key, iv []byte) {
	x := 0
	if !client {
		x = 8
	}

	bufA := make([]byte, len(msgKey)+36)
	copy(bufA, msgKey)
	copy(bufA[len(msgKey):], authKey[x:x+36])
	shaA := Sha256Sum(bufA)

	bufB := make([]byte, 36+len(msgKey))
	copy(bufB, authKey[x+40:x+76])
	copy(bufB[36:], msgKey)
	shaB := Sha256Sum(bufB)

	key = make([]byte, 32)
	copy(key[0:8], shaA[0:8])
	copy(key[8:24], shaB[8:24])
	copy(key[24:32], shaA[24:32])

	iv = make([]byte, 32)
	copy(iv[0:8], shaB[0:8])
	copy(iv[8:24], shaA[8:24])
	copy(iv[24:32], shaB[24:32])
	return
}

// ──────────────────────────────────────────────────────────────────────────────
// RSA encryption for MTProto key exchange
// ──────────────────────────────────────────────────────────────────────────────

// Soroush RSA public keys — fingerprint → modulus N
var SoroushRSAKeys = map[uint64]*big.Int{
	1756106365847508527: bigFromDecimal(""),
	4512654018935143700: bigFromDecimal(""),
	3954552239731554950: bigFromDecimal(""),
	3840879616129353640: bigFromDecimal(""),
	9721673155303707927: bigFromDecimal(""),
	7327245710266107682: bigFromDecimal(""),
	7311641324696334512: bigFromDecimal(""),
	5524002727329132702: bigFromDecimal(""),
	2155561823286592012: bigFromDecimal(""),
}

var rsaE = big.NewInt(65537)

func bigFromDecimal(s string) *big.Int {
	n := new(big.Int)
	n.SetString(s, 10)
	return n
}

func RSAEncrypt(data []byte, fingerprint uint64) (uint64, []byte, error) {
	n, ok := SoroushRSAKeys[fingerprint]
	if !ok {
		return 0, nil, fmt.Errorf("no RSA key for fingerprint %d", fingerprint)
	}

	for i := 0; i < 20; i++ {
		randomBytes := make([]byte, 32)
		rand.Read(randomBytes)

		dataWithPad := make([]byte, 192)
		copy(dataWithPad, data)
		rand.Read(dataWithPad[len(data):])

		dataRev := make([]byte, 192)
		for j := 0; j < 192; j++ {
			dataRev[j] = dataWithPad[191-j]
		}

		hashBuf := make([]byte, 32+192)
		copy(hashBuf, randomBytes)
		copy(hashBuf[32:], dataWithPad)
		msgKeyHash := Sha256Sum(hashBuf)

		s := append(dataRev, msgKeyHash...)
		encrypted := AesIGEEncrypt(s, randomBytes, make([]byte, 32))
		x := XorBytes(randomBytes, Sha256Sum(encrypted))
		candidate := append(x, encrypted...)

		num := new(big.Int).SetBytes(candidate)
		if num.Cmp(n) < 0 {
			result := new(big.Int).Exp(num, rsaE, n)
			resultBytes := make([]byte, 256)
			rb := result.Bytes()
			copy(resultBytes[256-len(rb):], rb)
			return fingerprint, resultBytes, nil
		}
	}
	return 0, nil, fmt.Errorf("RSA-PAD: failed after 20 tries")
}
